import React, { useEffect, useState } from 'react'
import styled from 'styled-components'
import { useParams } from 'react-router-dom'
import db from '../firebase'

function Detail() {

    const { id } = useParams();
    const [ movie, setMovie ] = useState();

    useEffect(() => {
        //Grab movie info from DB
        db.collection("movies").doc(id).get().then((doc) => {
            if(doc.exists){
                // save the movie data
                setMovie(...doc.data());
            }
            else{
                //redirect to home page
            }
        })
    }, [])
    console.log("This is movie", movie);
    return (
        <Container>
            <Background>
                <img src="#" />
            </Background>

            <ImgTitle>
                <img src={ movie.titleImg}/>
            </ImgTitle>

            <Controls>
                <PlayBtn>
                    <img src="/images/play-icon-black.png" />
                    <span>Play</span>
                </PlayBtn>
                
                <TrailerBtn>
                    <img src="/images/play-icon-white.png" />
                    <span>Trailer</span>
                </TrailerBtn>

                <AddBtn>
                    <span>+</span>
                </AddBtn>

                <GroupWatchBtn>
                <img src="/images/group-icon.png" />
                </GroupWatchBtn>
            </Controls>

            <SubTitle>
                2018- 7m- Family, Fantasy, Animation, Drama
            </SubTitle>

            <Description>
                An aging and lonely Chinese-Canadian mother, 
                suffering from empty nest syndrome, who receives 
                an unexpected second chance at motherhood when she makes 
                a steamed bun (baozi) that comes to life.
            </Description>
        </Container>
    )
}

export default Detail;

const Container = styled.div`
    min-height: calc(100vh - 70px);
    padding: 0 calc(3.5vw + 5px);
    position: relative;
`

const Background = styled.div`
    position: fixed;
    top: 0;
    left: 0;
    bottom: 0;
    right: 0;
    z-index: -1;
    opacity: 0.8;

    img {
        height: 100%;
        width: 100%;
        object-fit: cover;
    }
`

const ImgTitle = styled.div`
    height: 30vh;
    min-height: 170px;
    width: 35vw;
    min-width: 200px;
    margin-top: 60px;
    margin-bottom: 30px;
    img {
        height: 100%;
        width: 100%;
        object-fit: contain;
    }
`

const Controls = styled.div`
    display: flex;
    align-items: center;
`

const PlayBtn = styled.button`
    border-radius: 4px;
    font-size: 15px;
    display: flex;
    align-items: center;
    height: 50px;
    background: rgb(249, 249, 249);
    padding: 0 24px;
    margin-right: 22px;
    border: none;
    letter-spacing: 1.8px;
    cursor: pointer;
    text-transform: uppercase;

    &:hover {
        background: rgb(198, 198, 198); 
    }
`

const TrailerBtn = styled(PlayBtn)`
    background: rgba(0, 0, 0, 0.3);
    border: 1px solid rgb(249, 249, 249);
    color: rgb(249, 249, 249);
`

const AddBtn = styled.button`
    margin-right: 22px;
    height: 44px;
    width: 44px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    border: 2px solid white;
    background-color: rgb(0, 0, 0, 0.6);
    cursor: pointer;

    span {
        font-size: 30px;
        color: white;
    }

    &:hover {
        background: rgb(198, 198, 198);
    }
`

const GroupWatchBtn = styled(AddBtn)`
    background: rgb(0, 0, 0)
`

const SubTitle = styled.div`
    color: rgb(249, 249, 249);
    font-size: 15px;
    min-height: 20px;
    margin-top:26px;
`

const Description = styled.div`
    line-height: 1.4;
    font-size: 20px;
    margin-top: 16px;
    color: rgb(249, 249, 249);
    max-width: 760px;

`
